    const auto sqrt1430 = std::sqrt(1430.0);
    const auto sqrt2002 = std::sqrt(2002.0);
    const auto sqrt2145 = std::sqrt(2145.0);
    const auto sqrt2310 = std::sqrt(2310.0);
    const auto sqrt2431 = std::sqrt(2431.0);
