    d[76] = Y6_p0 * Y5_p5 * V[0] + ((315.0 / 4862.0) * sqrt1001 * Y9_p5 + (-1050.0 / 2431.0) * sqrt66 * Y7_p5 * R2 + (15.0 / 13.0) * Y5_p5 * R4) * V[1] + ((525.0 / 286.0) * sqrt66 * Y7_p5 + (-225.0 / 26.0) * Y5_p5 * R2) * V[2] + 18.75 * Y5_p5 * V[3];
    d[70] = Y6_p0 * Y5_n1 * V[0] + ((-147.0 / 187.0) * sqrt3 * Y9_n1 + (-30.0 / 221.0) * sqrt105 * Y7_n1 * R2 + (-12.0 / 13.0) * Y5_n1 * R4 + (15.0 / 22.0) * sqrt15 * Y1_n1 * R8) * V[1] + ((15.0 / 26.0) * sqrt105 * Y7_n1 + (90.0 / 13.0) * Y5_n1 * R2 - 7.5 * sqrt15 * Y1_n1 * R6) * V[2] + (-15.0 * Y5_n1 + 33.75 * sqrt15 * Y1_n1 * R4) * V[3] - 59.0625 * sqrt15 * Y1_n1 * R2 * V[4] + 29.53125 * sqrt15 * Y1_n1 * V[5];
    d[69] = Y6_p0 * Y5_n2 * V[0] + ((-21.0 / 2431.0) * sqrt462 * Y9_n2 + (945.0 / 2431.0) * sqrt10 * Y7_n2 * R2 + (36.0 / 13.0) * Y5_n2 * R4 + (210.0 / 143.0) * sqrt7 * Y3_n2 * R6) * V[1] + ((-945.0 / 572.0) * sqrt10 * Y7_n2 + (-270.0 / 13.0) * Y5_n2 * R2 + (-315.0 / 22.0) * sqrt7 * Y3_n2 * R4) * V[2] + (45.0 * Y5_n2 + 52.5 * sqrt7 * Y3_n2 * R2) * V[3] - 59.0625 * sqrt7 * Y3_n2 * V[4];
